import { EventCategory } from '@/types';
import { Toast } from '@/hooks/use-toast'; //  إذا كان عندك use-toast مخصص، import النوع من هون

export const deleteEvent = async (
  token: string,
  event: EventCategory,
  setEvents: React.Dispatch<React.SetStateAction<EventCategory[]>>,
  setSelectedEvent: React.Dispatch<React.SetStateAction<EventCategory | null>>,
  setIsDeleteDialogOpen: React.Dispatch<React.SetStateAction<boolean>>,
  toast?: Toast['toast'] // نوع toast الصحيح
) => {
  if (!event?._id) return;

  try {
    const res = await fetch(`http://localhost:8080/host/events/${event._id}`, {
      method: 'DELETE',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
    });

    const data = await res.json();

    if (!res.ok) {
      throw new Error(data.message || 'Failed to delete event');
    }

    // ✅ إزالة الحدث من الواجهة مباشرة بعد نجاح الحذف
    setEvents((prev) => prev.filter((e) => e._id !== event._id));

    toast({
      title: 'Event Deleted',
      description: data.message || 'Event deleted successfully.',
      className: 'bg-green-600 text-white border-0',
    });
  } catch (error: any) {
    toast({
      title: 'Error',
      description: error?.message || 'An unexpected error occurred.',
      className: 'bg-red-500 text-white border-0',
    });
  } finally {
    setIsDeleteDialogOpen(false);
    setSelectedEvent(null);
  }
};
